def run_command(command, description, cwd=None, env=None):
    """Run a shell command and handle errors."""
    logger.info(f"Starting: {description}")
    logger.info(f"Command: {' '.join(command) if isinstance(command, list) else command}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            command,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout:
            for line in result.stdout.strip().split("\n"):
                logger.info(f"  {line}")

        if result.returncode != 0:
            logger.error(f"Failed: {description}")
            if result.stderr:
                for line in result.stderr.strip().split("\n"):
                    logger.error(f"  {line}")
            return False

        logger.info(f"Completed: {description}")
        return True

    except subprocess.TimeoutExpired:
        logger.error(f"Timeout: {description} exceeded 300s limit")
        return False
    except FileNotFoundError:
        logger.error(f"Command not found: {command[0] if isinstance(command, list) else command}")
        return False
    except Exception as e:
        logger.error(f"Unexpected error during '{description}': {e}")
        return False


def check_prerequisites():
    """Verify all prerequisites are met before deployment."""
    logger.info("=" * 60)
    logger.info("PHASE 1: Checking prerequisites")
    logger.info("=" * 60)

    errors = []

    # Check Python version
    python_version = sys.version_info
    logger.info(f"Python version: {python_version.major}.{python_version.minor}.{python_version.micro}")
    if python_version < (3, 8):
        errors.append(f"Python 3.8+ required, found {python_version.major}.{python_version.minor}")

    # Check pip is available
    if not run_command([sys.executable, "-m", "pip", "--version"], "Checking pip availability"):
        errors.append("pip is not available")

    # Check requirements.txt exists
    if not os.path.isfile(REQUIREMENTS_FILE):
        errors.append(f"requirements.txt not found at {REQUIREMENTS_FILE}")
    else:
        logger.info(f"Found requirements.txt at {REQUIREMENTS_FILE}")

    # Check for test directory or test files
    test_locations = [
        os.path.join(PROJECT_ROOT, "tests"),
        os.path.join(PROJECT_ROOT, "test"),
        os.path.join(PROJECT_ROOT, "test_*.py"),
    ]
    has_tests = any(os.path.exists(loc) for loc in test_locations)
    if not has_tests:
        # Also check for any test_*.py files in project root
        import glob
        test_files = glob.glob(os.path.join(PROJECT_ROOT, "test_*.py"))
        test_files += glob.glob(os.path.join(PROJECT_ROOT, "**/test_*.py"), recursive=True)
        has_tests = len(test_files) > 0

    if not has_tests:
        logger.warning("No test directory or test files found - tests phase will be skipped")

    if errors:
        for error in errors:
            logger.error(f"Prerequisite failed: {error}")
        return False

    logger.info("All prerequisites met")
    return True


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    logger.info("=" * 60)
    logger.info("PHASE 2: Installing dependencies")
    logger.info("=" * 60)

    # Upgrade pip first
    run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )

    # Install production dependencies
    success = run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", REQUIREMENTS_FILE,
            "--no-cache-dir",
            "--disable-pip-version-check",
        ],
        "Installing production dependencies from requirements.txt",
    )

    if not success:
        return False

    # Install test dependencies if a test requirements file exists
    test_req_files = [
        os.path.join(PROJECT_ROOT, "requirements-test.txt"),
        os.path.join(PROJECT_ROOT, "requirements_test.txt"),
        os.path.join(PROJECT_ROOT, "test-requirements.txt"),
    ]

    for test_req in test_req_files:
        if os.path.isfile(test_req):
            logger.info(f"Found test requirements: {test_req}")
            success = run_command(
                [
                    sys.executable, "-m", "pip", "install",
                    "-r", test_req,
                    "--no-cache-dir",
                ],
                f"Installing test dependencies from {os.path.basename(test_req)}",
            )
            if not success:
                return False
            break

    # Ensure pytest is available for testing
    run_command(
        [sys.executable, "-m", "pip", "install", "pytest", "pytest-cov", "--quiet"],
        "Ensuring pytest is available",
    )

    # Verify installed packages
    run_command(
        [sys.executable, "-m", "pip", "freeze"],
        "Listing installed packages",
    )

    logger.info("Dependencies installed successfully")
    return True


