def run_tests():
    """Run the application test suite."""
    logger.info("=" * 60)
    logger.info("PHASE 3: Running tests")
    logger.info("=" * 60)

    # Determine test directory
    test_dir = None
    for candidate in ["tests", "test"]:
        candidate_path = os.path.join(PROJECT_ROOT, candidate)
        if os.path.isdir(candidate_path):
            test_dir = candidate_path
            break

    # Check for pytest.ini, setup.cfg, or pyproject.toml for test config
    has_config = any(
        os.path.isfile(os.path.join(PROJECT_ROOT, f))
        for f in ["pytest.ini", "setup.cfg", "pyproject.toml", "tox.ini"]
    )

    # Build pytest command
    pytest_args = [
        sys.executable, "-m", "pytest",
        "-v",
        "--tb=short",
        "--strict-markers",
        "-x",  # Stop on first failure for fast feedback
    ]

    # Add coverage if source directory exists
    src_dir = None
    for candidate in ["src", "app", "lib"]:
        if os.path.isdir(os.path.join(PROJECT_ROOT, candidate)):
            src_dir = candidate
            break

    if src_dir:
        pytest_args.extend([
            f"--cov={src_dir}",
            "--cov-report=term-missing",
            "--cov-report=html:build/coverage",
            "--cov-fail-under=0",  # Don't fail on coverage threshold by default
        ])

    # Add test directory if found and no config file handles it
    if test_dir and not has_config:
        pytest_args.append(test_dir)

    # Set environment for testing
    test_env = {
        "PYTHONPATH": PROJECT_ROOT,
        "TESTING": "1",
        "ENV": "test",
    }

    success = run_command(pytest_args, "Running test suite", env=test_env)

    if not success:
        logger.error("Tests failed - aborting deployment")
        return False

    logger.info("All tests passed")
    return True


def compute_file_hash(filepath):
    """Compute SHA256 hash of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


